class Solution:
    def maxValueOfCoins(self, piles, k):
        n = len(piles)
        best = [0]

        def rec(i, remaining, total):
            if total > best[0]:
                best[0] = total
            if i == n or remaining == 0:
                return
            cur = 0
            limit = min(len(piles[i]), remaining)
            for c in range(0, limit + 1):
                rec(i + 1, remaining - c, total + cur)
                if c < limit:
                    cur += piles[i][c]

        rec(0, k, 0)
        return best[0]

