class Solution:
    def maxValueOfCoins(self, piles, k):
        n = len(piles)
        prefix = []
        for pile in piles:
            p = [0]
            for c in pile:
                p.append(p[-1] + c)
            prefix.append(p)
        dp = [0] * (k + 1)
        for i in range(n):
            new_dp = dp[:]
            p = prefix[i]
            max_take = len(piles[i])
            for j in range(k + 1):
                best = dp[j]
                limit = min(max_take, j)
                for c in range(1, limit + 1):
                    val = dp[j - c] + p[c]
                    if val > best:
                        best = val
                new_dp[j] = best
            dp = new_dp
        return dp[k]

