var maxValueOfCoins = function(piles, k) {
    const n = piles.length;
    const prefix = piles.map(pile => {
        const p = [0];
        for (const c of pile) p.push(p[p.length - 1] + c);
        return p;
    });
    let dp = new Array(k + 1).fill(0);
    for (let i = 0; i < n; i++) {
        const newDp = dp.slice();
        const p = prefix[i];
        const maxTake = piles[i].length;
        for (let j = 0; j <= k; j++) {
            let best = dp[j];
            const limit = Math.min(maxTake, j);
            for (let c = 1; c <= limit; c++) {
                const val = dp[j - c] + p[c];
                if (val > best) best = val;
            }
            newDp[j] = best;
        }
        dp = newDp;
    }
    return dp[k];
};
